class Solution:
    def productExceptSelf(self, nums: list[int]) -> list[int]:
        n = len(nums)
        ans = [1] * n
        # 第一遍:ans[i] = 它左边所有数的乘积(左前缀积)
        for i in range(1, n):
            ans[i] = ans[i - 1] * nums[i - 1]
        # 第二遍:从右往左,用 right 累计右边乘积,乘进 ans[i]
        right = 1
        for i in range(n - 1, -1, -1):
            ans[i] *= right             # 左积 × 右积 = 除自身外的乘积
            right *= nums[i]            # 更新右侧累计积
        return ans
